def _calculation_view_to_nested(
    calculation_view: CalculationView,
) -> CalculationViewNested:
    """Convert flat CalculationView to nested format."""
    attrs = CalculationViewAttributes()
    _populate_calculation_view_attrs(attrs, calculation_view)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        calculation_view,
        _CALCULATION_VIEW_REL_FIELDS,
        CalculationViewRelationshipAttributes,
    )
    return CalculationViewNested(
        guid=calculation_view.guid,
        type_name=calculation_view.type_name,
        status=calculation_view.status,
        version=calculation_view.version,
        create_time=calculation_view.create_time,
        update_time=calculation_view.update_time,
        created_by=calculation_view.created_by,
        updated_by=calculation_view.updated_by,
        classifications=calculation_view.classifications,
        classification_names=calculation_view.classification_names,
        meanings=calculation_view.meanings,
        labels=calculation_view.labels,
        business_attributes=calculation_view.business_attributes,
        custom_attributes=calculation_view.custom_attributes,
        pending_tasks=calculation_view.pending_tasks,
        proxy=calculation_view.proxy,
        is_incomplete=calculation_view.is_incomplete,
        provenance_type=calculation_view.provenance_type,
        home_id=calculation_view.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _calculation_view_from_nested(nested: CalculationViewNested) -> CalculationView:
    """Convert nested format to flat CalculationView."""
    attrs = (
        nested.attributes
        if nested.attributes is not UNSET
        else CalculationViewAttributes()
    )
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _CALCULATION_VIEW_REL_FIELDS,
        CalculationViewRelationshipAttributes,
    )
    return CalculationView(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_calculation_view_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _calculation_view_to_nested_bytes(
    calculation_view: CalculationView, serde: Serde
) -> bytes:
    """Convert flat CalculationView to nested JSON bytes."""
    return serde.encode(_calculation_view_to_nested(calculation_view))


def _calculation_view_from_nested_bytes(data: bytes, serde: Serde) -> CalculationView:
    """Convert nested JSON bytes to flat CalculationView."""
    nested = serde.decode(data, CalculationViewNested)
    return _calculation_view_from_nested(nested)


